"""Validate the multi-zone blueprint YAML and dump its structure."""
import yaml


class HALoader(yaml.SafeLoader):
    pass


def _passthrough(loader, node):
    if isinstance(node, yaml.ScalarNode):
        return loader.construct_scalar(node)
    if isinstance(node, yaml.SequenceNode):
        return loader.construct_sequence(node)
    return loader.construct_mapping(node)


for tag in ("!input", "!secret", "!include"):
    HALoader.add_constructor(tag, _passthrough)


with open("smart_multi_zone_schedule.yaml") as fh:
    data = yaml.load(fh, Loader=HALoader)

inputs = data["blueprint"]["input"]
print(f"Blueprint: {data['blueprint']['name']}")
print(f"Inputs ({len(inputs)}):")
for k in inputs:
    print(f"  - {k}")

opts = inputs["operating_mode"]["selector"]["select"]["options"]
print(f"\noperating_mode options ({len(opts)}):")
for o in opts:
    print(f"  - {o['value']}: {o['label']}")

"""Validate the multi-zone adaptive watering blueprint."""
import yaml


class HALoader(yaml.SafeLoader):
    pass


def _passthrough(loader, node):
    if isinstance(node, yaml.ScalarNode):
        return loader.construct_scalar(node)
    if isinstance(node, yaml.SequenceNode):
        return loader.construct_sequence(node)
    return loader.construct_mapping(node)


for tag in ("!input", "!secret", "!include"):
    HALoader.add_constructor(tag, _passthrough)


with open("smart_multi_zone_schedule.yaml") as fh:
    data = yaml.load(fh, Loader=HALoader)

bp = data["blueprint"]
inputs = bp["input"]
vars_ = data["variables"]
triggers = data["trigger"]

print(f"Blueprint: {bp['name']}")
print(f"Triggers ({len(triggers)}):")
for t in triggers:
    print(f"  - {t.get('platform')} (id={t.get('id', 'n/a')})")

print(f"\nInputs ({len(inputs)}):")
for k, v in inputs.items():
    default = v.get("default", "<required>")
    sel = list(v.get("selector", {}).keys())[0] if v.get("selector") else "?"
    print(f"  - {k:38s} [{sel:10s}] default={default!r}")

print(f"\nVariables ({len(vars_)}):")
for k in vars_:
    print(f"  - {k}")

# Count notifications
import re
yaml_text = open("smart_multi_zone_schedule.yaml").read()
titles = re.findall(r'title:\s*"([^"]+)"', yaml_text)
titles += re.findall(r'title:\s*([^\n"]+)\n', yaml_text)
notif_titles = [t.strip() for t in titles if any(ord(c) > 127 for c in t)]
print(f"\nNotification titles ({len(notif_titles)}):")
for t in sorted(set(notif_titles)):
    print(f"  - {t}")

"""Final validation after renaming rain_sensor_today → rain_sensor."""
import yaml
import re


class HALoader(yaml.SafeLoader):
    pass


def _passthrough(loader, node):
    if isinstance(node, yaml.ScalarNode):
        return loader.construct_scalar(node)
    if isinstance(node, yaml.SequenceNode):
        return loader.construct_sequence(node)
    return loader.construct_mapping(node)


for tag in ("!input", "!secret", "!include"):
    HALoader.add_constructor(tag, _passthrough)


with open("smart_multi_zone_schedule.yaml") as fh:
    yaml_text = fh.read()
    data = yaml.load(yaml_text, Loader=HALoader)

bp = data["blueprint"]
inputs = bp["input"]
vars_ = data["variables"]

print(f"Blueprint: {bp['name']}")
print(f"Inputs ({len(inputs)}):")
for k in inputs:
    print(f"  - {k}")

# Search for any leftover references
print("\nLeftover-reference search:")
for term in ["rain_today_mm", "rain_sensor_today", "Rain today"]:
    n = len(re.findall(re.escape(term), yaml_text))
    print(f"  {term:25s} {'❌ FOUND' if n else '✅ clean'} ({n})")

# Search for the new label being used everywhere
print("\nNew-label usage:")
for term in ["rain_recent_mm", "rain_label", "Rain {{ rain_label }}"]:
    n = len(re.findall(re.escape(term), yaml_text))
    print(f"  {term:25s} {'✅' if n else '❌'} ({n})")

# Check inputs are well-formed
print(f"\nNew/renamed inputs:")
for k in ["rain_sensor", "rain_period_label"]:
    if k in inputs:
        print(f"  ✅ {k:20s} default={inputs[k].get('default', '<required>')!r}")
    else:
        print(f"  ❌ {k:20s} MISSING")

import yaml
class L(yaml.SafeLoader):
    pass
def pt(l, n):
    if isinstance(n, yaml.ScalarNode): return l.construct_scalar(n)
    if isinstance(n, yaml.SequenceNode): return l.construct_sequence(n)
    return l.construct_mapping(n)
L.add_constructor('!input', pt)
d = yaml.load(open('smart_fountain_schedule.yaml'), Loader=L)
print('OK', d['blueprint']['name'])
print('inputs', len(d['blueprint']['input']), 'vars', len(d['variables']), 'triggers', len(d['trigger']))
